        "def build_arg_parser():",
        "    parser = argparse.ArgumentParser()",
        "    parser.add_argument('--condition', '--conditions', dest='conditions', action='append', default=None)",
        "    return parser",
        "",
        "def _locked_condition_names():",
        "    if 'LOCKED_CONDITIONS' in globals():",
