        "def _run_locked_conditions(config: Any, prepared: Mapping[str, Any]) -> OrderedDict[str, Dict[str, Any]]:",
        "    results: OrderedDict[str, Dict[str, Any]] = OrderedDict()",
        "    for condition in _locked_condition_order(config):",
