        ") -> Any:",
        "    cls = _condition_config_class()",
        "    metadata = {'marker': marker, 'recipe_type': recipe_type, 'notes': list(notes or [])}",
        "    desired_values = {",
        "        'marker': marker,",
        "        'display_name': display_name,",
